class Solution:
    def repeatedStringMatch(self, a: str, b: str) -> int:
        n, m = len(a), len(b)
        q, r = divmod(m, n)
        res = q
        if r:
            res += 1
        if b not in a * res:
            if b not in a * (res + 1):
                return -1
            else:
                return res + 1
        return res

